#include <stdio.h>
#include <string.h>

int toMinutes(const char *s){
    int hh, mm; char ampm[3];
    sscanf(s, "%d:%d %2s", &hh, &mm, ampm);
    if (hh == 12) hh = 0;
    if (strcmp(ampm, "PM") == 0) hh += 12;
    return hh*60 + mm;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    char line[30];
    while(T--){
        // read meeting time (may contain space)
        scanf(" %[^\n]", line);
        int P = toMinutes(line);
        int N; scanf("%d", &N);
        char ans[505];
        for(int i=0;i<N;i++){
            char L[30], R[30];
            scanf(" %[^ ] %[^\n]", L, R);
            int l = toMinutes(L);
            int r = toMinutes(R);
            ans[i] = (l <= P && P <= r) ? '1' : '0';
        }
        ans[N] = '\0';
        printf("%s\n", ans);
    }
    return 0;
}

