#include <bits/stdc++.h>
using namespace std;

int toMinutes(const string &s){
    int hh = stoi(s.substr(0,2));
    int mm = stoi(s.substr(3,2));
    string ampm = s.substr(6,2);
    if(hh == 12) hh = 0;
    if(ampm == "PM") hh += 12;
    return hh*60 + mm;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    string dummy; getline(cin,dummy); // consume endline
    while(T--){
        string Pstr; getline(cin,Pstr);
        int P = toMinutes(Pstr);
        int N; cin>>N; getline(cin,dummy);
        string result; result.reserve(N);
        for(int i=0;i<N;i++){
            string L,R; cin>>L>>R; getline(cin,dummy);
            int l = toMinutes(L), r = toMinutes(R);
            result.push_back((l<=P && P<=r)?'1':'0');
        }
        cout<<result<<"\n";
    }
    return 0;
}

