const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\n/);
let idx = 0;
function toMinutes(s){
  const hh = parseInt(s.slice(0,2),10);
  const mm = parseInt(s.slice(3,5),10);
  const ampm = s.slice(6,8);
  let h = hh===12?0:hh;
  if(ampm === 'PM') h += 12;
  return h*60 + mm;
}
const T = parseInt(input[idx++],10);
let outputs = [];
for(let t=0;t<T;t++){
  const Pstr = input[idx++];
  const P = toMinutes(Pstr);
  const N = parseInt(input[idx++],10);
  let res = '';
  for(let i=0;i<N;i++){
    const parts = input[idx++].split(' ');
    const l = toMinutes(parts[0]);
    const r = toMinutes(parts[1]);
    res += (l <= P && P <= r) ? '1' : '0';
  }
  outputs.push(res);
}
